var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"쉿, 말하지 않아도 다 알아.","JPN":"しーっ、言わなくてもわかってるわ。","ENG":" Shh, don't say anything.","TWN":"噓，你不必說，我都知道。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"내 계약을 원하는 거지? 얼마든지 해주고 말고.","JPN":"アタシに契約してほしいのよね？　いくらでもしてあげる。","ENG":" You want to enter a contract with me, right? I thought you'd never ask.","TWN":"你想要和我簽訂契約對吧？我完全沒問題～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그냥… 테이블을 사이에 두고 술도 없이 얘기만 하는 건 내 취향이 아니거든.","JPN":"ただ……テーブル越しにお酒もなく話し合うのはアタシの好みじゃないの。","ENG":" Just talking across the table without any drinks isn't my style.","TWN":"只是…我談事情時一向習慣要有酒。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"뭐, 계약이니까 관행상 경고를 살짝 해주긴 할 거야. 나중에 후회해도 난 몰라~ 같은 거지.","JPN":"まあ、契約だし、しきたりとして一応警告しておくわ。後で後悔してもアタシは知らないわよーみたいな。","ENG":" Well, we're entering into a contract, so I have to give you a warning, for formality's sake. \\"Don't say I didn't warn you,\\" that sort of thing.","TWN":"既然是契約，按規矩我還是必須體醒你一下，日後反悔的話我可不管喔～類似這種話。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"뭘 후회하냐고?","JPN":"何を後悔するかって？","ENG":" Why?","TWN":"為什麼會反悔嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"후훗, 시치미 떼긴. 손님도 대강은 알고 있잖아? 나 같은 여자랑 약속을 하면 끝이 좋지 않다는 거.","JPN":"フフッ、とぼけちゃって。アナタだって\\n大体わかってるでしょ？　アタシみたいな女と約束を交わして、いい結末はないって。","ENG":" Hah hah, don't pretend you don't know. You know, at least to an extent, entering into a contract with a woman like me always ends in tears.","TWN":"呵呵，你明明就知道，還故意裝傻。和我種女人簽約，下場通常是不太好的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그래, 그래. 나중의 일은 나중이지. 어쩌면 이번 계약에는 해피엔딩이란 게 있을 지 누가 알겠어?","JPN":"まあまあ、後のことは後でいっか。もしかしたら今回の契約はハッピーエンドになるかもね！","ENG":" Yeah, yeah. We can worry about that later. Besides, who knows? I might have a happy ending this time?","TWN":"好吧～以後的事以後再說。誰也說不定，或許這次的契約會是快樂大結局呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그럼 언젠가 맞게 될 해피엔딩을 기념하는 의미로… 한잔할까?","JPN":"それでは、いつか迎えるハッピーエンドを記念して……一杯どう？","ENG":" Alright, then how'd you like to drink to our distant happy ending?","TWN":"那我們就當作是慶祝總有一天會到來的快樂大結局…喝一杯嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"걱정 마. 혹시라도 쓰러지면 내가 우리 집에 데려다줄게.","JPN":"心配しないで。もし酔いつぶれたらアタシがお持ち帰りしてあげる。","ENG":" Don't worry. If you pass out, I can take you home with me.","TWN":"別擔心，萬一你喝醉的話，我會把你撿回家～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};